#!/usr/bin/env bash

###############################################################################
# GEOIP RouterOS Builder
###############################################################################

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"

source "${SCRIPT_DIR}/common.sh"

###############################################################################
# Prepare
###############################################################################

info "Preparing"

ensure_directory "$OUTPUT_DIR"

###############################################################################
# Download sing-box
###############################################################################

if [[ ! -x "$SINGBOX_BINARY" ]]
then

    info "Downloading sing-box ${SINGBOX_VERSION}"

    wget -q \
        "$SINGBOX_URL" \
        -O sing-box.tar.gz

    tar -xzf sing-box.tar.gz

    chmod +x "$SINGBOX_BINARY"

    rm -f sing-box.tar.gz

fi

###############################################################################
# Download SRS
###############################################################################

info "Downloading ${SOURCE_NAME}"

wget -q \
    "$SRS_URL" \
    -O "$SRS_FILE"

###############################################################################
# Decompile
###############################################################################

info "Decompiling"

"$SINGBOX_BINARY" \
    rule-set decompile \
    --output "$JSON_FILE" \
    "$SRS_FILE"

###############################################################################
# Validate JSON
###############################################################################

require_file "$JSON_FILE"

validate_json

###############################################################################
# Generate CURRENT.TXT
###############################################################################

info "Generating IPv4 list"

generate_ipv4_txt

check_txt_prefix_count

###############################################################################
# First run
###############################################################################

if ! file_exists "$TXT_FILE"
then

    info "Initial build"

    "${SCRIPT_DIR}/generate_full.sh"

    move_file "$CURRENT_TXT" "$TXT_FILE"

    rm -f "$ADD_RSC"
    rm -f "$DEL_RSC"

    info "Initial build completed."

    rm -f "$JSON_FILE"
    rm -f "$SRS_FILE"

    exit 0

fi

###############################################################################
# Compare
###############################################################################

if files_equal "$TXT_FILE" "$CURRENT_TXT"
then

    info "No changes detected."

    rm -f "$CURRENT_TXT"
    rm -f "$JSON_FILE"
    rm -f "$SRS_FILE"

    exit 0

fi

###############################################################################
# Generate FULL
###############################################################################

"${SCRIPT_DIR}/generate_full.sh"

###############################################################################
# Generate DIFF
###############################################################################

"${SCRIPT_DIR}/generate_diff.sh"

###############################################################################
# Cleanup
###############################################################################

rm -f "$JSON_FILE"
rm -f "$SRS_FILE"

info "Build completed."
